import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatNumber } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { DefectiveSummaryRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-sp-loi';
const PAGE_ID = 'baocao-sp-loi';

const BaoCaoSpLoiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [rows, setRows] = useState<DefectiveSummaryRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getDefectiveSummary({ fromDate, toDate })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
      />
    ),
    [fromDate, toDate, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Sản phẩm lỗi"
      titleIconClass="fas fa-exclamation-triangle"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/wms/reports/defective-summary/export-excel"
      exportParams={{ fromDate, toDate }}
      exportFilename={`SPLoi-${fromDate}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Mã</th>
            <th>Tên</th>
            <th className={reportStyles.colRight}>SL</th>
            <th>Loại lỗi</th>
            <th>Kho</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>{r.productCode}</td>
              <td>{r.productName}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.quantity)}</td>
              <td>{r.defectType ?? '—'}</td>
              <td>{r.warehouseName ?? '—'}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoSpLoiPage;
